.min-demo-container {
    position: relative;
    width: 100%;
    height: 100%;
    min-height: 320px;
    background: linear-gradient(135deg, #FAFAFA 0%, #F5F5F5 100%);
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    padding: 3rem 2rem;
    overflow: hidden;
  }

  /* 頂部裝飾线 */
  .min-demo-line-accent {
    position: absolute;
    top: 2rem;
    left: 50%;
    transform: translateX(-50%);
    width: 40px;
    height: 1px;
    background: #000;
    opacity: 0.2;
  }

  .min-demo-line-accent::before,
  .min-demo-line-accent::after {
    content: '';
    position: absolute;
    width: 3px;
    height: 3px;
    background: #000;
    border-radius: 50%;
    top: -1px;
  }

  .min-demo-line-accent::before {
    left: -8px;
  }

  .min-demo-line-accent::after {
    right: -8px;
  }

  /* 主內容区 */
  .min-demo-content {
    text-align: center;
    z-index: 1;
  }

  .min-demo-meta {
    font-size: 0.625rem;
