    line-height: 1.1;
    margin-bottom: 1.5rem;
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
  }

  .min-demo-heading-light {
    font-weight: 200;
    color: #666;
    letter-spacing: 0.05em;
  }

  .min-demo-heading-bold {
    font-weight: 600;
    color: #000;
    letter-spacing: -0.02em;
  }

  .min-demo-description {
    font-size: 0.875rem;
    font-weight: 300;
    color: #666;
    letter-spacing: 0.15em;
    opacity: 0.8;
  }

  /* 底部裝飾元素 */
  .min-demo-footer {
    position: absolute;
    bottom: 2rem;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    align-items: center;
    gap: 1rem;
  }

  .min-demo-dot {
    width: 4px;
    height: 4px;
    background: #000;
    border-radius: 50%;
    opacity: 0.3;
    animation: pulse 2s ease-in-out infinite;
  }

  .min-demo-footer-line {
