  border: none;
}

/* Minimalist Grid */
.minimal-grid {
  display: grid;
  grid-template-columns: repeat(12, 1fr);
  gap: 32px;
  margin-bottom: 64px;
}

/* Minimalist Card */
.minimal-card {
  background: #ffffff;
