     color: #f4f4f0;
     -webkit-text-stroke: 0px transparent;
   }
   ```

2. **Gradient Text Fill**
   ```css
   .text-gradient {
     background: linear-gradient(to right, #ffffff, #666666);
     -webkit-background-clip: text;
     background-clip: text;
     -webkit-text-fill-color: transparent;
   }
