        'clay-hover': '-6px -6px 16px rgba(255, 255, 255, 0.7), 6px 6px 16px rgba(255, 143, 179, 0.5), inset -2px -2px 4px rgba(255, 255, 255, 0.2), inset 2px 2px 4px rgba(255, 143, 179, 0.3)',
