/* 正方形容器（height = width） */
.fabric-demo-square {
  aspect-ratio: 1 / 1;
  width: 100%;
  background: linear-gradient(135deg, #f5f2ed 0%, #ebe8e3 100%);
  background-image:
    repeating-linear-gradient(
      90deg,
      transparent,
      transparent 3px,
      rgba(0, 0, 0, 0.015) 3px,
      rgba(0, 0, 0, 0.015) 6px
    ),
    repeating-linear-gradient(
      0deg,
      transparent,
      transparent 3px,
      rgba(0, 0, 0, 0.015) 3px,
      rgba(0, 0, 0, 0.015) 6px
    );
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 32px;
  padding: 40px;
  position: relative;
  overflow: hidden;
  border-radius: 12px;
}

/* 布料標籤樣式 */
.fabric-tag-label {
  background: linear-gradient(180deg, #e8dcc4 0%, #d4c5a9 100%);
  padding: 16px 40px;
  border-radius: 12px;
  box-shadow:
    0 6px 20px rgba(0, 0, 0, 0.15),
    inset 0 1px 0 rgba(255, 255, 255, 0.5);
  border: 2px solid rgba(255, 255, 255, 0.6);
  position: relative;
  background-image:
    repeating-linear-gradient(
      90deg,
      transparent,
      transparent 2px,
      rgba(0, 0, 0, 0.02) 2px,
      rgba(0, 0, 0, 0.02) 4px
    );
}

/* 標籤釘子 */
.tag-pin {
  position: absolute;
  top: -6px;
  left: 50%;
  transform: translateX(-50%);
  width: 12px;
  height: 12px;
  background: radial-gradient(circle, #8b7355 0%, #6b5845 100%);
  border-radius: 50%;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.3);
}

.tag-pin::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 4px;
  height: 4px;
  background: rgba(255, 255, 255, 0.3);
  border-radius: 50%;
}

/* 標籤文字 */
.tag-text {
  font-size: 32px;
  font-weight: 700;
  color: #2c3e50;
  text-shadow: 0 1px 0 rgba(255, 255, 255, 0.6);
  letter-spacing: 1px;
}

/* 標籤縫線 */
.tag-stitch {
