  bottom: 8px;
  left: 16px;
  right: 16px;
  border-bottom: 2px dashed rgba(0, 0, 0, 0.2);
}

/* 三個布料樣本網格 */
.fabric-swatches-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 20px;
  width: 100%;
  max-width: 320px;
}

/* 小型布料樣本 */
.fabric-mini-swatch {
  aspect-ratio: 1 / 1;
  border-radius: 12px;
