}

/* 帆布樣本 */
.canvas-mini {
  background: #d4c5a9;
  background-image:
    repeating-linear-gradient(
      45deg,
      transparent,
      transparent 3px,
      rgba(0, 0, 0, 0.03) 3px,
      rgba(0, 0, 0, 0.03) 6px
    ),
    repeating-linear-gradient(
      -45deg,
      transparent,
      transparent 3px,
      rgba(0, 0, 0, 0.03) 3px,
      rgba(0, 0, 0, 0.03) 6px
    );
}

/* 牛仔布樣本 */
.denim-mini {
  background: #4a5f7f;
  background-image:
    repeating-linear-gradient(
