  margin-top: 10px;
}

.sticky-note:hover {
  transform: rotate(0deg) scale(1.05);
  box-shadow:
    0 10px 20px rgba(0, 0, 0, 0.15),
    0 3px 6px rgba(0, 0, 0, 0.1);
