}

.note-yellow {
  background: linear-gradient(135deg, #fff9c4 0%, #fff59d 100%);
}

.note-pink {
  background: linear-gradient(135deg, #fce4ec 0%, #f8bbd0 100%);
}

.note-blue {
  background: linear-gradient(135deg, #e1f5fe 0%, #b3e5fc 100%);
}

.sticky-note h3 {
  margin: 0 0 12px 0;
  font-family: 'Caveat', cursive;
  font-size: 28px;
  font-weight: 700;
  color: #2c3e50;
}

.sticky-note p {
