  background-color: var(--memphis-magenta);
  border: 4px solid var(--memphis-black);
  border-radius: 50%;
  cursor: pointer;
  transform: rotate(15deg);
  box-shadow: 4px 4px 0 var(--memphis-black);
  transition: all 0.3s ease;
