}

.mono-nav-notification-dot {
  position: absolute;
  top: 0.25rem;
  right: 0.25rem;
  width: 8px;
  height: 8px;
  background: var(--mono-black);
  border-radius: 50%;
}

/* 用户头像 */
.mono-avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--mono-gray-400), var(--mono-gray-600));
  border: 2px solid var(--mono-white);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}
