}

.btn-primary:hover {
  background: #2563EB; /* 稍深的蓝 */
  box-shadow: var(--scandi-shadow-md);
  transform: translateY(-2px);
}

.btn-primary:active {
  transform: translateY(0);
  box-shadow: var(--scandi-shadow-xs);
}

/* 次按钮：白底 + 灰边 */
.btn-secondary {
  background: var(--scandi-white);
  color: var(--scandi-text-primary);
  padding: 10px 24px;
  border-radius: var(--radius-lg);
  font-size: 14px;
  font-weight: 500;
  border: 1px solid var(--scandi-bg-dark);
  cursor: pointer;
  transition: all 200ms ease;
}

.btn-secondary:hover {
  background: var(--scandi-bg-light);
  border-color: var(--scandi-blue);
  color: var(--scandi-blue);
}

/* 成功按钮 */
.btn-success {
  background: var(--scandi-green);
  color: white;
  padding: 10px 24px;
  border-radius: var(--radius-lg);
  font-size: 14px;
  font-weight: 500;
  border: none;
  cursor: pointer;
  box-shadow: var(--scandi-shadow-sm);
  transition: all 200ms ease;
}

.btn-success:hover {
  background: #059669;
  box-shadow: var(--scandi-shadow-md);
}

/* 圆形小按钮 - 适合 icon */
.btn-icon {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: var(--scandi-bg-light);
  border: 1px solid var(--scandi-bg-dark);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 200ms ease;
  color: var(--scandi-text-secondary);
}

.btn-icon:hover {
  background: var(--scandi-white);
