  box-shadow: var(--hud-glow-red);
}

/* 成功按钮 */
.hud-btn-success {
  border-color: rgba(34, 197, 94, 0.4);
  color: var(--hud-success);
}

.hud-btn-success:hover {
  border-color: var(--hud-success);
  box-shadow: var(--hud-glow-green);
}

/* 按钮图标 */
.hud-btn-icon {
  font-size: 1.125rem;
}

/* 按钮标签 */
.hud-btn-label {
  font-size: 0.75rem;
}
```

