/* ===== Container ===== */
.smoke-demo {
  background: linear-gradient(135deg, #0a1628 0%, #051020 50%, #0d1b2e 100%);
  min-height: 500px;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  overflow: hidden;
  width: 100%;
  height: 100%;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

/* 環境光暈 (增強對比度) */
.smoke-demo::before {
  content: '';
  position: absolute;
  bottom: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 400px;
  height: 300px;
  background: radial-gradient(
    ellipse at center,
    rgba(120, 150, 200, 0.12) 0%,
    rgba(80, 110, 160, 0.06) 40%,
    transparent 70%
  );
  pointer-events: none;
  z-index: 1;
}

/* ===== Smoke Container ===== */
.smoke-container {
  position: absolute;
  width: 100%;
  height: 100%;
  top: 0;
  left: 0;
  pointer-events: none;
}

/* ===== Smoke Layers (Maximum Visibility) ===== */
.smoke-layer {
  position: absolute;
  border-radius: 50%;
  filter: blur(25px);
  will-change: transform, opacity;
  z-index: 2;
}

.smoke-layer-1 {
  width: 250px;
  height: 340px;
  background: radial-gradient(
    ellipse at center,
    rgba(240, 245, 255, 0.95) 0%,
    rgba(200, 210, 235, 0.75) 40%,
    rgba(160, 175, 205, 0.5) 70%,
    rgba(120, 140, 180, 0.2) 90%,
    transparent 100%
  );
  bottom: 0px;
  left: 50%;
  transform: translateX(-50%);
  animation: denseSmoke1 12s ease-in-out infinite;
}

.smoke-layer-2 {
  width: 310px;
  height: 390px;
  background: radial-gradient(
    ellipse at center,
    rgba(235, 242, 255, 0.98) 0%,
    rgba(195, 208, 235, 0.78) 45%,
    rgba(155, 170, 200, 0.52) 75%,
    rgba(115, 135, 170, 0.22) 90%,
    transparent 100%
  );
  bottom: 10px;
  left: 40%;
  animation: denseSmoke2 14s ease-in-out infinite;
  animation-delay: 2s;
}

.smoke-title {
  position: relative;
  font-family: 'Space Grotesk', 'Inter', sans-serif;
  font-size: clamp(36px, 6vw, 72px);
  letter-spacing: 0.4em;
  color: #ffffff;
  text-transform: uppercase;
  z-index: 6;
  mix-blend-mode: screen;
  text-align: center;
  padding-left: 0.4em;
}

.smoke-layer-3 {
  width: 280px;
  height: 360px;
  background: radial-gradient(
    ellipse at center,
    rgba(238, 244, 255, 0.96) 0%,
    rgba(198, 210, 238, 0.76) 42%,
    rgba(158, 173, 203, 0.5) 72%,
    rgba(118, 138, 173, 0.2) 90%,
    transparent 100%
  );
  bottom: 5px;
  left: 60%;
  animation: denseSmoke3 13s ease-in-out infinite;
  animation-delay: 4s;
}

.smoke-layer-4 {
  width: 340px;
  height: 420px;
  background: radial-gradient(
    ellipse at center,
    rgba(232, 240, 255, 1.0) 0%,
    rgba(192, 206, 232, 0.8) 48%,
    rgba(152, 168, 197, 0.54) 76%,
    rgba(112, 133, 167, 0.24) 90%,
    transparent 100%
  );
  bottom: 15px;
  left: 35%;
  animation: denseSmoke4 15s ease-in-out infinite;
  animation-delay: 6s;
}

.smoke-layer-5 {
  width: 295px;
  height: 380px;
  background: radial-gradient(
    ellipse at center,
    rgba(236, 243, 255, 0.97) 0%,
    rgba(196, 209, 235, 0.77) 44%,
    rgba(156, 171, 200, 0.51) 74%,
    rgba(116, 136, 170, 0.21) 90%,
    transparent 100%
  );
  bottom: 8px;
  left: 55%;
  animation: denseSmoke5 13.5s ease-in-out infinite;
  animation-delay: 8s;
}

.smoke-layer-6 {
  width: 265px;
  height: 350px;
  background: radial-gradient(
    ellipse at center,
    rgba(240, 246, 255, 0.95) 0%,
    rgba(200, 212, 238, 0.75) 46%,
    rgba(160, 175, 203, 0.49) 73%,
    rgba(120, 140, 178, 0.19) 90%,
    transparent 100%
  );
  bottom: 12px;
  left: 45%;
  animation: denseSmoke6 14.5s ease-in-out infinite;
  animation-delay: 10s;
}

/* ===== Smoke Animations (Curling Effect) ===== */
@keyframes denseSmoke1 {
  0% {
    transform: translate(-50%, 0) scale(1) rotate(0deg);
    opacity: 0;
  }
  10% {
    opacity: 0.85;
  }
  25% {
    transform: translate(calc(-50% - 20px), -120px) scale(1.3) rotate(25deg);
    opacity: 0.9;
  }
  50% {
    transform: translate(calc(-50% + 15px), -240px) scale(1.6) rotate(50deg);
    opacity: 0.7;
  }
  75% {
    transform: translate(calc(-50% - 25px), -360px) scale(1.9) rotate(75deg);
    opacity: 0.4;
  }
  100% {
    transform: translate(calc(-50% + 10px), -480px) scale(2.2) rotate(100deg);
    opacity: 0;
  }
}

@keyframes denseSmoke2 {
  0% {
    transform: translate(0, 0) scale(1) rotate(0deg);
    opacity: 0;
  }
  10% {
    opacity: 0.9;
  }
  30% {
    transform: translate(35px, -140px) scale(1.35) rotate(-30deg);
    opacity: 0.95;
  }
  60% {
    transform: translate(-20px, -280px) scale(1.7) rotate(-60deg);
    opacity: 0.6;
  }
  100% {
    transform: translate(30px, -450px) scale(2.1) rotate(-90deg);
    opacity: 0;
  }
}

@keyframes denseSmoke3 {
  0% {
    transform: translate(0, 0) scale(1) rotate(0deg);
    opacity: 0;
  }
  10% {
    opacity: 0.82;
  }
  28% {
    transform: translate(-30px, -130px) scale(1.32) rotate(35deg);
    opacity: 0.88;
  }
  56% {
    transform: translate(25px, -260px) scale(1.64) rotate(70deg);
    opacity: 0.65;
  }
  100% {
    transform: translate(-20px, -440px) scale(2.0) rotate(105deg);
    opacity: 0;
  }
}

@keyframes denseSmoke4 {
  0% {
    transform: translate(0, 0) scale(1) rotate(0deg);
    opacity: 0;
  }
  10% {
    opacity: 0.92;
  }
  32% {
    transform: translate(40px, -150px) scale(1.4) rotate(-40deg);
    opacity: 0.96;
  }
  64% {
    transform: translate(-25px, -300px) scale(1.8) rotate(-80deg);
    opacity: 0.55;
  }
  100% {
    transform: translate(35px, -470px) scale(2.3) rotate(-120deg);
    opacity: 0;
  }
}

@keyframes denseSmoke5 {
  0% {
    transform: translate(0, 0) scale(1) rotate(0deg);
    opacity: 0;
  }
  10% {
    opacity: 0.84;
  }
  27% {
    transform: translate(-35px, -135px) scale(1.33) rotate(28deg);
    opacity: 0.87;
  }
  54% {
    transform: translate(20px, -270px) scale(1.66) rotate(56deg);
    opacity: 0.62;
  }
  100% {
    transform: translate(-25px, -445px) scale(2.05) rotate(84deg);
    opacity: 0;
  }
}

@keyframes denseSmoke6 {
  0% {
    transform: translate(0, 0) scale(1) rotate(0deg);
    opacity: 0;
  }
  10% {
    opacity: 0.86;
  }
  29% {
    transform: translate(32px, -138px) scale(1.36) rotate(-32deg);
    opacity: 0.91;
  }
  58% {
    transform: translate(-22px, -276px) scale(1.72) rotate(-64deg);
    opacity: 0.58;
  }
  100% {
    transform: translate(28px, -455px) scale(2.15) rotate(-96deg);
    opacity: 0;
  }
}

/* ===== Minimal Glow Source ===== */
.smoke-source {
  position: absolute;
  bottom: 30px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 5;
}

.glow-dot {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: radial-gradient(circle,
    rgba(220, 235, 255, 1) 0%,
    rgba(180, 205, 240, 0.8) 40%,
    rgba(140, 175, 225, 0.4) 70%,
    transparent 100%
  );
  box-shadow:
    0 0 30px rgba(200, 220, 255, 0.9),
    0 0 60px rgba(170, 195, 235, 0.6),
    0 0 90px rgba(140, 170, 215, 0.4),
    0 0 120px rgba(110, 145, 195, 0.2);
  animation: breathe 3s ease-in-out infinite;
}

@keyframes breathe {
  0%, 100% {
    opacity: 1;
    transform: scale(1);
  }
  50% {
    opacity: 0.6;
    transform: scale(0.85);
  }
}

/* ===== Responsive ===== */
@media (max-width: 768px) {
  .smoke-demo {
    min-height: 400px;
  }

  .smoke-layer-1 { width: 180px; height: 240px; }
  .smoke-layer-2 { width: 220px; height: 280px; }
  .smoke-layer-3 { width: 200px; height: 260px; }
  .smoke-layer-4 { width: 240px; height: 300px; }
  .smoke-layer-5 { width: 210px; height: 270px; }
  .smoke-layer-6 { width: 190px; height: 250px; }

  .glow-dot {
    width: 16px;
    height: 16px;
  }
}

/* ===== Performance Optimization ===== */
@media (prefers-reduced-motion: reduce) {
  .smoke-layer {
    animation: none !important;
    opacity: 0.3;
  }

  .glow-dot {
    animation: none !important;
  }
}

custom.zh-CN:
创建一个具有 **Soft UI Light（浅色软 UI）** 风格的现代应用界面，在浅色背景上使用柔和的内外阴影创造微妙的深度感，营造平静、舒适、亲和的视觉体验，使用 TailwindCSS 实现。

### 核心视觉特征

**浅色 Soft UI 设计语言**：
- 背景使用柔和的浅灰色 `#e4e7eb` 或浅蓝灰色 `#eceff4`
- 元素使用与背景相近的颜色，通过阴影创造深度
- 凸起元素（按钮、卡片）使用双向柔和阴影：
  - 左上浅色阴影（高光）：`box-shadow: -8px -8px 16px rgba(255, 255, 255, 0.8)`
  - 右下深色阴影（暗部）：`box-shadow: 8px 8px 16px rgba(163, 177, 198, 0.3)`
- 凹陷元素（输入框、内容区）使用内阴影：
  - 内阴影：`box-shadow: inset 3px 3px 6px rgba(163, 177, 198, 0.3), inset -3px -3px 6px rgba(255, 255, 255, 0.8)`
- 所有元素采用圆润的圆角（12px-20px），强调柔和触感

**浅色柔和色彩系统**：
- 主背景：浅灰 `#e4e7eb`
- 卡片背景：与背景相同或略浅 `#e8eaed`
- 凸起元素：与背景相同（通过阴影区分）
- 凹陷元素：略深于背景 `#d8dce3`
- 文字颜色：
  - 主文字：深灰 `#3c4043`
  - 次要文字：中灰 `#5f6368`
  - 禁用文字：浅灰 `#9aa0a6`
- 强调色：
  - 主要：柔和蓝色 `#4285f4`
  - 次要：柔和紫色 `#a142f4`
  - 成功：柔和绿色 `#34a853`
  - 警告：柔和橙色 `#fbbc04`
  - 危险：柔和红色 `#ea4335`

**阴影与深度系统**：
- 浅层凸起（小按钮）：阴影偏移 ±4px，模糊 8px
- 中层凸起（卡片）：阴影偏移 ±8px，模糊 16px
- 深层凸起（大卡片）：阴影偏移 ±12px，模糊 24px
- 浅层凹陷（输入框）：内阴影偏移 ±2px，模糊 4px
- 深层凹陷（内容区）：内阴影偏移 ±4px，模糊 8px

### 页面结构与组件

**浅色 Soft UI 应用布局**：
```
┌────────────────────────────────────────────────┐
│  [Logo] 首页 产品 服务 关于  [搜索] [登入]   │ ← 顶部栏（凸起）
├────────────────────────────────────────────────┤
│                                                 │
│  ┌──────────────────────────────────────────┐  │
│  │  ☀️ 早上好！                             │  │
│  │  开始您美好的一天                       │  │ ← Hero 卡片（凸起）
│  │  [开始探索] [了解更多]                   │  │
│  └──────────────────────────────────────────┘  │
│                                                 │
│  ┌─────┐ ┌─────┐ ┌─────┐ ┌─────┐             │
│  │ 🎯  │ │ 📊  │ │ 💡  │ │ 🚀  │             │
│  │ 任务│ │ 数据│ │ 创意│ │ 目标│             │ ← 功能卡片（凸起）
│  │ 12  │ │ 45  │ │ 8   │ │ 3   │             │
│  └─────┘ └─────┘ └─────┘ └─────┘             │
│                                                 │
│  ┌────────────────────────────────────────┐    │
│  │ 设定面板                               │    │
│  │ ┌────────────────────────────────────┐ │    │ ← 内容区（凹陷）
│  │ │ 姓名：[Tom Leung ]                 │ │    │
│  │ │ 邮箱：[tom@example.com]            │ │    │
│  │ │ 通知：[开启切换器]                  │ │    │
│  │ │ [保存设定]（凸起按钮）              │ │    │
│  │ └────────────────────────────────────┘ │    │
│  └────────────────────────────────────────┘    │
└────────────────────────────────────────────────┘
```

**核心组件样式**：

**凸起按钮**：
```css
.soft-light-btn {
  background: #e4e7eb;
  border-radius: 12px;
  padding: 12px 24px;
  color: #3c4043;
  font-weight: 600;
  box-shadow:
    -6px -6px 12px rgba(255, 255, 255, 0.8),
    6px 6px 12px rgba(163, 177, 198, 0.3);
  transition: all 0.3s ease;
}

.soft-light-btn:hover {
  box-shadow:
    -8px -8px 16px rgba(255, 255, 255, 0.9),
    8px 8px 16px rgba(163, 177, 198, 0.4);
}

.soft-light-btn:active {
  box-shadow:
    inset 3px 3px 6px rgba(163, 177, 198, 0.3),
    inset -3px -3px 6px rgba(255, 255, 255, 0.8);
}
```

**主要按钮（彩色）**：
```css
.soft-light-btn-primary {
  background: linear-gradient(135deg, #5a9bff 0%, #4285f4 100%);
  border-radius: 12px;
  padding: 12px 24px;
  color: white;
  font-weight: 600;
  box-shadow:
    -4px -4px 8px rgba(90, 155, 255, 0.2),
    4px 4px 8px rgba(66, 133, 244, 0.4);
  transition: all 0.3s ease;
}

.soft-light-btn-primary:hover {
  box-shadow:
    -6px -6px 12px rgba(90, 155, 255, 0.3),
    6px 6px 12px rgba(66, 133, 244, 0.5);
  transform: translateY(-2px);
}
```

**凹陷输入框**：
```css
.soft-light-input {
  background: #e4e7eb;
  border-radius: 10px;
  padding: 12px 16px;
  border: none;
  color: #3c4043;
  box-shadow:
    inset 3px 3px 6px rgba(163, 177, 198, 0.3),
    inset -3px -3px 6px rgba(255, 255, 255, 0.8);
  transition: all 0.3s ease;
}

.soft-light-input:focus {
  outline: none;
  box-shadow:
    inset 4px 4px 8px rgba(163, 177, 198, 0.4),
    inset -4px -4px 8px rgba(255, 255, 255, 0.9),
    0 0 0 3px rgba(66, 133, 244, 0.2);
