  font-weight: 800;
  font-size: 1.5rem;
  background: var(--y2k-rainbow);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.y2k-nav-links {
  display: flex;
  gap: 2rem;
  list-style: none;
  margin: 0;
  padding: 0;
}

.y2k-nav-link {
