/* ===== Reset & Base ===== */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Source Sans 3', -apple-system, BlinkMacSystemFont, sans-serif;
  background: #FAF9F6;
  color: #1a1a1a;
  line-height: 1.75;
  font-size: 16px;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

.magazine-container {
  max-width: 1000px;
  margin: 0 auto;
  padding: 3rem 2rem;
  background: #fff;
  box-shadow: 0 0 60px rgba(0, 0, 0, 0.05);
}

/* ===== Magazine Header ===== */
.magazine-header {
  margin-bottom: 4rem;
  position: relative;
}

.header-ornament-top {
  height: 3px;
  background: linear-gradient(90deg,
    transparent 0%,
    #1a1a1a 15%,
    #1a1a1a 85%,
    transparent 100%
  );
  margin-bottom: 2rem;
}

.header-content {
  text-align: center;
  padding: 1.5rem 0;
}

.issue-meta {
  font-size: 0.7rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: #888;
  margin-bottom: 1.5rem;
  font-weight: 400;
}

.issue-divider {
  margin: 0 0.75rem;
  color: #ccc;
}

.masthead {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 1.5rem;
  margin-bottom: 1rem;
}

.masthead-line {
  width: 60px;
  height: 1px;
  background: #1a1a1a;
}

.magazine-title {
  font-family: 'Playfair Display', serif;
  font-size: 3.5rem;
  font-weight: 400;
  letter-spacing: 0.4em;
  margin: 0;
  position: relative;
}

.tagline {
  font-size: 0.75rem;
  letter-spacing: 0.15em;
  color: #666;
  font-style: italic;
  font-weight: 300;
}

.magazine-nav {
  display: flex;
  justify-content: center;
  gap: 3rem;
  margin-top: 2rem;
  padding: 1.5rem 0;
}

.nav-item {
  font-size: 0.75rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: #666;
  text-decoration: none;
  position: relative;
  font-weight: 400;
  transition: color 0.3s ease;
}

.nav-item::after {
  content: '';
  position: absolute;
  bottom: -8px;
  left: 50%;
  transform: translateX(-50%);
  width: 0;
  height: 2px;
  background: #1a1a1a;
  transition: width 0.3s ease;
}

.nav-item:hover,
.nav-item.active {
  color: #1a1a1a;
}

.nav-item:hover::after,
.nav-item.active::after {
  width: 100%;
}

.header-ornament-bottom {
  height: 1px;
  background: linear-gradient(90deg,
    transparent 0%,
    #e0e0e0 20%,
    #e0e0e0 80%,
    transparent 100%
  );
  margin-top: 2rem;
}

/* ===== Hero Feature ===== */
.hero-feature {
  position: relative;
  margin-bottom: 4rem;
}

.feature-number {
  position: absolute;
  top: -1rem;
  left: -1rem;
  font-family: 'Playfair Display', serif;
  font-size: 6rem;
  font-weight: 700;
  color: #f5f5f5;
  z-index: 0;
  line-height: 1;
}

.hero-layout {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4rem;
  align-items: center;
  position: relative;
  z-index: 1;
}

.hero-image-wrapper {
  position: relative;
}

.image-frame {
  position: relative;
  padding: 1rem;
  background: linear-gradient(135deg, #fafafa 0%, #f0f0f0 100%);
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.08);
}

.hero-image {
  aspect-ratio: 3/4;
  background: linear-gradient(135deg, #e8e8e8 0%, #d4d4d4 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.placeholder-label {
  font-size: 0.8rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: #999;
  font-weight: 600;
}

.image-credit {
  margin-top: 1rem;
  display: flex;
  justify-content: space-between;
  font-size: 0.7rem;
  letter-spacing: 0.1em;
}

.credit-label {
  text-transform: uppercase;
  color: #888;
  font-weight: 600;
}

.credit-name {
  font-style: italic;
  color: #666;
}

.hero-text {
  padding: 2rem 0;
}

.article-label {
  display: flex;
  align-items: center;
  gap: 1rem;
  margin-bottom: 2rem;
}

.label-line {
  width: 30px;
  height: 1px;
  background: #ccc;
}

.label-text {
  font-size: 0.65rem;
  letter-spacing: 0.25em;
  color: #888;
  font-weight: 600;
}

.hero-title {
  font-family: 'Playfair Display', serif;
  font-size: 3.5rem;
  font-weight: 400;
  line-height: 1.15;
  margin-bottom: 1.5rem;
  letter-spacing: -0.02em;
}

.hero-subtitle {
  font-size: 1.15rem;
  color: #555;
  line-height: 1.8;
  margin-bottom: 2rem;
  font-weight: 300;
}

.hero-meta {
  display: flex;
  gap: 2rem;
  align-items: center;
  margin-bottom: 2rem;
  padding: 1.5rem 0;
  border-top: 1px solid #e8e8e8;
  border-bottom: 1px solid #e8e8e8;
}

.meta-group {
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
}

.meta-label {
  font-size: 0.65rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: #999;
  font-weight: 600;
}

.meta-value {
  font-size: 0.9rem;
  color: #333;
  font-weight: 400;
}

.meta-divider {
  width: 1px;
  height: 40px;
  background: #e0e0e0;
}

.read-more {
  display: inline-flex;
  align-items: center;
  gap: 0.75rem;
  font-size: 0.8rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: #1a1a1a;
  font-weight: 600;
  cursor: pointer;
  transition: gap 0.3s ease;
}

.read-more:hover {
  gap: 1.25rem;
}

.read-more-arrow {
  font-size: 1.2rem;
  transition: transform 0.3s ease;
}

.read-more:hover .read-more-arrow {
  transform: translateX(4px);
}

/* ===== Article Body ===== */
.article-body {
  margin-bottom: 4rem;
}

.body-layout {
  display: grid;
  grid-template-columns: 2fr 1fr;
  gap: 4rem;
}

.main-content {
  padding-right: 2rem;
}

.drop-cap-paragraph {
  margin-bottom: 1.5rem;
  text-align: justify;
  hyphens: auto;
  font-size: 1.05rem;
  line-height: 1.9;
  color: #333;
}

.dropcap {
  font-family: 'Playfair Display', serif;
  font-size: 5.5rem;
  font-weight: 400;
  float: left;
  line-height: 0.75;
  margin: 0.15rem 0.6rem 0 0;
  color: #1a1a1a;
}

.body-text {
  margin-bottom: 1.5rem;
  text-align: justify;
  hyphens: auto;
  font-size: 1.05rem;
  line-height: 1.9;
  color: #333;
  font-weight: 300;
}

.inline-image {
  margin: 2.5rem 0;
}

.inline-image-frame {
  background: #f8f8f8;
  padding: 1rem;
}

.inline-placeholder {
  aspect-ratio: 16/9;
  background: linear-gradient(135deg, #1a1a1a 0%, #444 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 1rem;
}

.inline-number {
  font-family: 'Playfair Display', serif;
  font-size: 4rem;
  color: rgba(255, 255, 255, 0.3);
  font-weight: 700;
}

.inline-caption {
  font-size: 0.8rem;
  color: #666;
  font-style: italic;
  line-height: 1.6;
}

.section-heading {
  font-family: 'Playfair Display', serif;
  font-size: 1.8rem;
  font-weight: 400;
  margin: 2.5rem 0 1.5rem;
  color: #1a1a1a;
}

/* ===== Sidebar ===== */
.sidebar {
  padding-left: 2rem;
  border-left: 1px solid #e8e8e8;
}

.pull-quote {
  padding: 2rem 0;
  margin-bottom: 2.5rem;
  position: relative;
}

.quote-mark {
  font-family: 'Playfair Display', serif;
  font-size: 6rem;
  color: #e8e8e8;
  position: absolute;
  top: -1rem;
  left: -0.5rem;
  line-height: 1;
}

.quote-text {
  font-family: 'Playfair Display', serif;
  font-size: 1.25rem;
  font-style: italic;
  line-height: 1.7;
  color: #1a1a1a;
  margin-bottom: 1rem;
  position: relative;
  z-index: 1;
}

.quote-author {
  display: block;
  font-size: 0.75rem;
  letter-spacing: 0.1em;
  color: #888;
  font-style: normal;
  font-weight: 600;
}

.stats-box {
  background: #fafafa;
  padding: 2rem;
  margin-bottom: 2.5rem;
  border: 1px solid #e8e8e8;
}

.stat-item {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  text-align: center;
}

.stat-number {
  font-family: 'Playfair Display', serif;
  font-size: 2.5rem;
  color: #1a1a1a;
  font-weight: 700;
}

.stat-label {
  font-size: 0.75rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: #666;
  font-weight: 600;
}

.stat-divider {
  height: 1px;
  background: #e0e0e0;
  margin: 1.5rem 0;
}

.related-box {
  padding: 2rem 0;
}

.related-title {
  font-family: 'Playfair Display', serif;
  font-size: 1.1rem;
  font-weight: 400;
  margin-bottom: 1.25rem;
  color: #1a1a1a;
}

.related-list {
  list-style: none;
}

.related-list li {
  margin-bottom: 1rem;
  padding-left: 1.5rem;
  position: relative;
}

.related-list li::before {
  content: '→';
  position: absolute;
  left: 0;
  color: #ccc;
  font-size: 0.9rem;
}

.related-list a {
  font-size: 0.9rem;
  color: #555;
  text-decoration: none;
  transition: color 0.3s ease;
  letter-spacing: 0.02em;
}

.related-list a:hover {
  color: #1a1a1a;
}

/* ===== Section Divider ===== */
.section-divider {
  text-align: center;
  margin: 3rem 0;
  position: relative;
}

.divider-ornament {
  font-size: 1rem;
  color: #ccc;
  position: relative;
  display: inline-block;
  padding: 0 2rem;
  background: #fff;
}

.section-divider::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg,
    transparent 0%,
    #e0e0e0 20%,
    #e0e0e0 80%,
    transparent 100%
  );
}

/* ===== Gallery Section ===== */
.gallery-section {
  margin-bottom: 4rem;
}

.gallery-header {
  text-align: center;
  margin-bottom: 3rem;
}

.gallery-title {
  font-family: 'Playfair Display', serif;
  font-size: 2.5rem;
  font-weight: 400;
  margin-bottom: 1rem;
  letter-spacing: 0.02em;
}

.gallery-subtitle {
  font-size: 1rem;
  color: #666;
  font-weight: 300;
  letter-spacing: 0.05em;
}

.gallery-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 3rem;
}

.gallery-item {
  position: relative;
}

.gallery-image {
  aspect-ratio: 1;
  background: linear-gradient(135deg, #1a1a1a 0%, #333 100%);
  margin-bottom: 1.5rem;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}

.gallery-number {
  font-family: 'Playfair Display', serif;
  font-size: 4rem;
  color: rgba(255, 255, 255, 0.15);
  font-weight: 700;
}

.gallery-category {
  position: absolute;
  top: 1rem;
  right: 1rem;
  font-size: 0.65rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.8);
  padding: 0.4rem 0.8rem;
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  font-weight: 600;
}

.gallery-item-title {
  font-family: 'Playfair Display', serif;
  font-size: 1.4rem;
  font-weight: 400;
  margin-bottom: 0.75rem;
  color: #1a1a1a;
}

.gallery-item-text {
  font-size: 0.9rem;
  color: #666;
  line-height: 1.7;
  margin-bottom: 1rem;
  font-weight: 300;
}

.gallery-link {
  font-size: 0.75rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: #1a1a1a;
  text-decoration: none;
  font-weight: 600;
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  transition: gap 0.3s ease;
}

.gallery-link:hover {
  gap: 0.85rem;
}

/* ===== Magazine Footer ===== */
.magazine-footer {
  margin-top: 4rem;
  position: relative;
}

.footer-ornament {
  height: 1px;
  background: linear-gradient(90deg,
    transparent 0%,
    #e0e0e0 20%,
    #e0e0e0 80%,
    transparent 100%
  );
  margin-bottom: 2rem;
}

.footer-content {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 0.7rem;
  letter-spacing: 0.15em;
  color: #888;
}

.footer-left {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.footer-page {
  font-family: 'Playfair Display', serif;
  font-size: 1rem;
  color: #1a1a1a;
}

.footer-divider {
  color: #ccc;
}

.footer-magazine {
  text-transform: uppercase;
  font-weight: 600;
}

.footer-copyright {
  font-size: 0.65rem;
  color: #aaa;
}

/* ===== Responsive Design ===== */
@media (max-width: 768px) {
  .magazine-container {
    padding: 2rem 1.5rem;
  }

  .magazine-title {
    font-size: 2.5rem;
    letter-spacing: 0.3em;
  }

  .hero-layout,
  .body-layout {
    grid-template-columns: 1fr;
    gap: 2rem;
  }

  .feature-number {
    font-size: 4rem;
  }

  .hero-title {
    font-size: 2.5rem;
  }

  .sidebar {
    padding-left: 0;
    border-left: none;
    border-top: 1px solid #e8e8e8;
    padding-top: 2rem;
  }

  .gallery-grid {
    grid-template-columns: 1fr;
  }

  .footer-content {
    flex-direction: column;
    gap: 1rem;
    text-align: center;
  }
}
